B.RA=new A.a4("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.a7B=s([B.Qq,B.SD,B.RF,B.RA],t.l)
B.Ya=new A.m(B.L,"Ba\u011flamda Modal Fiiller",null,B.a7B,null,null)
B.a11=new A.m(B.at,"\u2708\ufe0f S\u0131nav \u0130pucu",'Modal sorular\u0131nda yayg\u0131n tuzaklar:\n\u2022 "must checking" \u2192 YANLI\u015e (modal + yal\u0131n fiil, -ing de\u011fil)\n\u2022 "should to inspect" \u2192 YANLI\u015e (modal sonras\u0131nda "to" gelmez)\n\u2022 "must performed" \u2192 YANLI\u015e (edilgen i\xe7in "be" gerekli: must **be** performed)\n\nModal fiil + bo\u015fluk g\xf6r\xfcnce sor: etken mi yoksa edilgen anlam m\u0131 gerekiyor?',null,null,null)
