B.Sv=new A.a4("Cumulonimbus clouds must be avoided by at least 20 nautical miles.","K\xfcm\xfclonimbus bulutlar\u0131ndan en az 20 deniz mili uzak durulmal\u0131d\u0131r.","Cumulonimbus")
