B.Xw=new A.m(B.x,"Transponder neden \xf6nemlidir?",'Transponder, u\xe7a\u011f\u0131n radar ekran\u0131nda ATC taraf\u0131ndan tan\u0131nmas\u0131n\u0131 sa\u011flar. ATC her u\xe7a\u011fa \xf6zg\xfc bir "squawk" (transponder kodu) verir. Do\u011fru kodu girmek ve ATC talimatlar\u0131n\u0131 anlamak trafi\u011fin g\xfcvenli y\xf6netimi i\xe7in zorunludur.',null,null,null)
B.Xq=new A.m(B.v,"\ud83d\udce1 Transponder Komutlar\u0131 ve Modlar\u0131",'**Squawk komutlar\u0131:**\n\u2022 **"Squawk [code]"** \u2192 transponder\u0131 [kod] numaras\u0131na ayarla\n\u2022 **"Squawk ident"** \u2192 tan\u0131mlama butonuna bas (ATC ekranda seni parlak g\xf6r\xfcr)\n\u2022 **"Squawk standby"** \u2192 transponder\u0131 beklemede b\u0131rak\n\u2022 **"Squawk altitude"** \u2192 Mode C\'yi etkinle\u015ftir (irtifa bilgisi)\n\u2022 **"Confirm squawk"** \u2192 kodu do\u011frula\n\n**Acil durum kodlar\u0131:**\n\u2022 **7700** \u2192 genel acil durum (emergency)\n\u2022 **7600** \u2192 telsiz ar\u0131zas\u0131 (radio failure)\n\u2022 **7500** \u2192 ka\xe7\u0131r\u0131lma (hijack)\n\n**T\xfcrk\xe7e \xe7eviriler:**\n\u2022 Squawk \u2192 transponder kodu\n\u2022 Ident \u2192 tan\u0131mlama / kimlik bildirimi\n\u2022 Mode C \u2192 barometrik irtifa modu\n\u2022 Transponder \u2192 transponder / ikincil g\xf6zetleme radar\u0131 cevaplay\u0131c\u0131',null,null,null)
B.RT=new A.a4('"Turkish 5, squawk 2347, squawk altitude."',"Turkish 5, transponder kodunu 2347 yap, Mode C'yi etkinle\u015ftir.","squawk 2347 \u2026 squawk altitude")
