B.a26=new A.m(B.x,"Kalk\u0131\u015f \xf6ncesi s\xfcre\xe7","Her u\xe7u\u015fta pilot ve ATC aras\u0131nda ger\xe7ekle\u015fen standart ileti\u015fim s\u0131ras\u0131 \u015f\xf6yledir:\n\n1. **ATIS dinle** \u2014 aktif pist ve hava durumunu \xf6\u011fren\n2. **Delivery'den clearance al** \u2014 rota, transponder kodu, initial altitude\n3. **Ground'dan taxi talimat\u0131 al** \u2014 hangi yoldan piste gidilece\u011fi\n4. **Tower'dan kalk\u0131\u015f izni al** \u2014 \"cleared for takeoff\"",null,null,null)
B.a2q=new A.m(B.v,"Standart Kalk\u0131\u015f \u0130fadeleri",'**Clearance request:**\n"Request IFR clearance to [destination], [aircraft type], [stand number]."\n\n**Readback:**\n"Cleared to [dest] via [SID], squawk [code], [callsign]."\n\n**Pushback & startup:**\n"Request pushback and startup, stand [X]."\n"Pushback and startup approved, face [direction]."\n\n**Taxi:**\n"Taxi to holding point runway [X] via [taxiways]."\n"Hold short of runway [X]."\n\n**Takeoff:**\n"Runway [X], cleared for takeoff, wind [X] degrees [X] knots."',null,null,null)
