B.a2m=new A.m(B.x,"Acil durum dili kesin olmal\u0131d\u0131r","Acil durum ileti\u015fimleri ICAO ifade kurallar\u0131na uyar. C\xfcmle tamamlama sorular\u0131nda, c\xfcmlenin anlam\u0131n\u0131 **tam ve eksiksiz** dolduran kelime ya da ifadeyi se\xe7meniz gerekir.\n\nYanl\u0131\u015f se\xe7enekler \xe7o\u011funlukla mant\u0131kl\u0131 g\xf6r\xfcn\xfcr \u2014 anahtar, en **do\u011fru** havac\u0131l\u0131k terimini se\xe7mektir.",null,null,null)
B.YQ=new A.m(B.v,"\ud83d\udea8 Acil Durum Seviyeleri",'**MAYDAY** (\xd73) \u2014 Distress: immediate danger to life\n"MAYDAY MAYDAY MAYDAY \u2014 THY123 \u2014 engine fire \u2014 declaring emergency"\n\n**PAN-PAN** (\xd73) \u2014 Urgency: serious situation, not immediate danger\n"PAN-PAN PAN-PAN PAN-PAN \u2014 THY123 \u2014 medical emergency on board"\n\n**SQUAWK 7700** \u2014 General emergency\n**SQUAWK 7600** \u2014 Radio failure\n**SQUAWK 7500** \u2014 Unlawful interference (hijack)',null,null,null)
B.ZU=new A.m(B.v,"\ud83d\udce1 Acil Durum Kontrol Listesi Dili",'Acil durum kontrol listeleri \xf6zel c\xfcmle kal\u0131plar\u0131 kullan\u0131r:\n\u2022 "In the event of \u2026\u2026\u2026\u2026, the crew should\u2026"\n\u2022 "If \u2026\u2026\u2026\u2026 is observed, immediately\u2026"\n\u2022 "\u2026\u2026\u2026\u2026\u2026 and report to ATC"\n\u2022 "Declare \u2026\u2026\u2026\u2026\u2026 and request priority landing"\n\nYayg\u0131n fiiller: **declare, squawk, divert, dump, depressurize, evacuate, report**',null,null,null)
B.Rm=new A.a4("In the event of an engine fire, the crew must __________ the affected engine.","Motor yang\u0131n\u0131 durumunda, ekip etkilenen motoru kapatmal\u0131d\u0131r.","shut down")
