B.a1z=new A.m(B.x,"Acil durum terimleri neden kritiktir?","Acil durumlarda do\u011fru terminolojiyi bilmek hayat kurtar\u0131r. Pilot stres alt\u0131nda olsa bile standart ifadeler, ATC'nin an\u0131nda do\u011fru prosed\xfcr\xfc ba\u015flatmas\u0131n\u0131 sa\u011flar. ICAO, acil durum ileti\u015fimi i\xe7in net bir hiyerar\u015fi belirlemi\u015ftir.",null,null,null)
B.a28=new A.m(B.v,"\ud83c\udd98 Acil Durum Hiyerar\u015fisi",'**MAYDAY** (3 kez tekrar) \u2192 tehlike durumu (distress)\n\u2022 Can veya u\xe7ak tehlikede, acil yard\u0131m gerekiyor\n\u2022 "MAYDAY MAYDAY MAYDAY, [\xe7a\u011fr\u0131 i\u015fareti], [pozisyon], [problem], [niyet], [can say\u0131s\u0131]"\n\n**PAN-PAN** (3 kez tekrar) \u2192 aciliyet durumu (urgency)\n\u2022 Tehlike yak\u0131n de\u011fil ama acil yard\u0131m veya \xf6ncelik gerekiyor\n\u2022 Format MAYDAY ile ayn\u0131\n\n**SECURITE** (3 kez tekrar) \u2192 emniyet mesaj\u0131\n\u2022 Navigasyon tehlikesi veya \xf6nemli meteoroloji uyar\u0131s\u0131\n\n**Yayg\u0131n acil ifadeler:**\n\u2022 "Declaring emergency" \u2192 acil ilan ediyorum\n\u2022 "Minimum fuel" \u2192 minimum yak\u0131t (\xe7\u0131km\u0131yor ama \xf6ncelik ister)\n\u2022 "Fuel emergency" \u2192 yak\u0131t acil (can tehlikesi s\u0131n\u0131r\u0131)\n\u2022 "Engine failure/fire/smoke in cabin"\n\u2022 "Returning to departure airport"\n\u2022 "Request immediate landing"',null,null,null)
B.QH=new A.a4('"MAYDAY MAYDAY MAYDAY, Turkish 234, 40 miles north of Istanbul, engine fire, descending to 10,000 feet, request immediate return, 189 souls on board."',"Tam format: \xe7a\u011fr\u0131 \xd7 3 \u2192 u\xe7ak ID \u2192 pozisyon \u2192 problem \u2192 niyet \u2192 can.","MAYDAY \u2026 engine fire \u2026 request immediate return \u2026 souls on board")
B.RE=new A.a4('"PAN-PAN PAN-PAN PAN-PAN, Lufthansa 55, medical emergency on board, request priority landing, 2 crew 180 passengers."',"Can tehlikesi yok ama t\u0131bbi acil nedeniyle \xf6ncelikli ini\u015f talep ediliyor.","PAN-PAN \u2026 medical emergency \u2026 priority landing")
B.Rb=new A.a4('"Declaring minimum fuel, request direct routing to reduce flight time."',"Minimum yak\u0131t bildirimi \u2014 acil de\u011fil ama \xf6ncelik istiyor.","minimum fuel \u2026 direct routing")
