B.ZF=new A.m(B.x,"\u0130leri metinler karma\u015f\u0131k dilbilgisi yap\u0131lar\u0131 kullan\u0131r","Havac\u0131l\u0131k belgeleri, kaza raporlar\u0131 ve ICAO yay\u0131nlar\u0131, birden fazla yan c\xfcmleyi bir araya getiren karma\u015f\u0131k c\xfcmle yap\u0131lar\u0131 kullan\u0131r. \u0130leri d\xfczeyde, hem anlama hem de \xfcretim sorular\u0131nda bunlar\u0131 do\u011fru bir \u015fekilde ele almal\u0131s\u0131n\u0131z.",null,null,null)
B.Y_=new A.m(B.v,"S\u0131fat C\xfcmleleri",'**Defining** (no commas): identifies which one\n\u2192 "The component **that failed** was the hydraulic pump."\n\n**Non-defining** (with commas): adds extra information\n\u2192 "The hydraulic pump, **which had just been serviced**, failed."\n\n**Reduced relative clause** (participle phrase):\n\u2192 "The pilot **flying the aircraft** reported vibration." (= who was flying)\n\u2192 "The component **installed last week** is defective." (= that was installed)',null,null,null)
