B.a0U=new A.m(B.x,"Kaza raporlar\u0131 kesin hukuki ve teknik dil kullan\u0131r","ICAO Ek 13 kaza ara\u015ft\u0131rma raporlar\u0131, havac\u0131l\u0131ktaki en dilbilimsel a\xe7\u0131dan zorlay\u0131c\u0131 belgeler aras\u0131ndad\u0131r. Tek bir metinde hukuki kesinli\u011fi, edilgen yap\u0131lar\u0131, teknik do\u011frulu\u011fu ve nedensellik analizini bir araya getirirler.\n\nBu raporlardan \xe7eviri sorular\u0131, hem teknik anlam\u0131 hem de her ifadenin hukuki sonu\xe7lar\u0131n\u0131 anlamay\u0131 gerektirir.",null,null,null)
B.ZD=new A.m(B.v,"\u26a0\ufe0f Nedensellik Dili",'**Probable cause** \u2014 the primary factor judged to have produced the accident\n**Contributing factor** \u2014 a condition that increased risk but was not the primary cause\n**Causal factor** \u2014 any element in the cause chain\n\nCausal verbs and phrases:\n\u2022 "**led to**" = caused/resulted in (direct chain)\n\u2022 "**attributed to**" = judged as the cause\n\u2022 "**resulted in**" = produced this outcome\n\u2022 "**was a factor in**" = contributed but not sole cause\n\u2022 "**was consistent with**" = evidence matches this explanation',null,null,null)
B.a2_=new A.m(B.v,"\ud83d\udccb Soru\u015fturma Bulgular\u0131 Dili",'"The investigation **found** that\u2026" \u2192 formal finding\n"Evidence **indicated** that\u2026" \u2192 supported but not proven\n"**It could not be determined** whether\u2026" \u2192 insufficient evidence\n"The crew **failed to**\u2026" \u2192 did not perform required action\n"**Contrary to** the standard operating procedure\u2026" \u2192 SOP violation\n"The accident **is survivable** / **was not survivable**" \u2192 survivability finding\n"**Safety recommendation**" \u2192 formal advisory to prevent recurrence',null,null,null)
B.SC=new A.a4("The probable cause of the accident was the crew's failure to monitor fuel quantity.","Kazan\u0131n muhtemel nedeni, ekibin yak\u0131t miktar\u0131n\u0131 izlememesiydi.","probable cause")
B.RQ=new A.a4("It could not be determined whether the crew had received the updated weather information.","Ekibin g\xfcncellenmi\u015f hava durumu bilgisini al\u0131p almad\u0131\u011f\u0131 belirlenemedi.","It could not be determined")
B.Sy=new A.a4("The investigation attributed the loss of situational awareness to crew fatigue and inadequate CRM.","Soru\u015fturma, durum fark\u0131ndal\u0131\u011f\u0131n\u0131n kayb\u0131n\u0131 m\xfcrettebat yorgunlu\u011funa ve yetersiz EKY'ye ba\u011flad\u0131.","attributed to")
B.afi=s([B.SC,B.RQ,B.Sy],t.l)
B.a_D=new A.m(B.L,"Rapor Metni \xd6rnekleri",null,B.afi,null,null)
B.a2x=new A.m(B.at,"\u2708\ufe0f \xc7eviri S\u0131nav Stratejisi",'Kaza raporu \xe7eviri sorular\u0131 i\xe7in:\n\u2022 "**Probable cause**" \u2260 "possible cause" \u2014 tespit edilen EN MUHTEMEL nedendir\n\u2022 "**Contributing factor**" \u2260 "main reason" \u2014 ikincil, a\u011f\u0131rla\u015ft\u0131r\u0131c\u0131 bir ko\u015fuldur\n\u2022 "**Crew failed to**" = zorunlu bir eylem yap\u0131lmad\u0131 \u2014 do\u011frudan ihmal anlam\u0131 ta\u015f\u0131maz\n\u2022 "**It could not be determined**" = yetersiz kan\u0131t \u2014 "bilinmiyor" olarak \xe7evirmeyin\n\u2022 "**Contrary to SOP**" = prosed\xfcr ihlali \u2014 raporlarda her zaman ciddidir',null,null,null)
B.adO=s(["The accident was caused by an out-of-control aircraft hitting terrain","The aircraft was in controlled flight when it struck terrain","The crew controlled the aircraft into terrain intentionally","The terrain was controlled by ATC when the accident occurred"],t.s)
B.aon=new A.x(-300,B.ad,460,'"The accident was attributed to controlled flight into terrain." This means:',B.adO,1,B.q,null,null,null)
B.adh=s(["In accordance with SOPs","Violating or not following SOPs","Similar to SOPs in other companies","An improvement over SOPs"],t.s)
B.anN=new A.x(-301,B.ad,461,'"Contrary to standard operating procedures" means:',B.adh,1,B.q,null,null,null)
B.ad0=s(["The main cause was crew rest","Crew rest was one element that made the accident more likely","Crew rest alone caused the accident","The crew rested adequately"],t.s)
B.anD=new A.x(-302,B.ad,462,'"A contributing factor was the inadequate crew rest period." This means:',B.ad0,1,B.q,null,null,null)
B.a6_=s(["It is confirmed that","There was not enough evidence to establish","It is unlikely that","The investigation did not examine"],t.s)
B.amW=new A.x(-303,B.ad,463,'"It could not be determined whether\u2026" in a report means:',B.a6_,1,B.aV,null,null,null)
B.acP=s([B.aon,B.anN,B.anD,B.amW],t.C)
B.a10=new A.m(B.w,"Pratik Sorular",null,null,null,B.acP)
