B.a0o=new A.m(B.x,"T\xfcrb\xfclans neden \xf6zel ileti\u015fim gerektirir?","T\xfcrb\xfclans, yolcularda ve ekipte yaralanmaya yol a\xe7abilen en yayg\u0131n u\xe7u\u015f g\xfcvenli\u011fi sorunlar\u0131ndan biridir. Net ve sakin bir ileti\u015fim, pani\u011fi \xf6nler ve g\xfcvenli\u011fi art\u0131r\u0131r.",null,null,null)
B.a1m=new A.m(B.v,"T\xfcrb\xfclans Anonslar\u0131",'**\xd6ncesinde:**\n"Ladies and gentlemen, the captain has switched on the fasten seatbelt sign. Please return to your seats and fasten your seatbelts."\n"We are expecting some turbulence ahead. Please remain seated with your seatbelts fastened."\n\n**Servis durumu:**\n"Due to turbulence, cabin service has been suspended. Please remain seated."\n\n**Sonras\u0131nda:**\n"The captain has turned off the fasten seatbelt sign. You may now move about the cabin, however we recommend keeping your seatbelt fastened when seated."',null,null,null)
