B.ac3=s(["a more serious emergency","an urgency requiring assistance but not immediate danger to life","a routine communication","an engine failure"],t.s)
B.aoJ=new A.x(-235,B.t,2105,'"PAN PAN" compared to "MAYDAY" indicates:',B.ac3,1,B.q,null,null,null)
