B.a24=new A.m(B.x,"Hidrolik sistemler neden kritiktir?","U\xe7a\u011f\u0131n kontrol y\xfczeyleri, ini\u015f tak\u0131m\u0131 ve frenler hidrolik sistemle \xe7al\u0131\u015f\u0131r. Bu sistemin bak\u0131m dilini bilmek, AMM talimatlar\u0131n\u0131 do\u011fru okumak i\xe7in \u015fartt\u0131r.",null,null,null)
B.a2B=new A.m(B.v,"Hidrolik Terminoloji",'**Temel bile\u015fenler:**\n\u2022 Hydraulic reservoir \u2014 depo\n\u2022 Hydraulic pump (engine-driven / electric) \u2014 pompa\n\u2022 Pressure relief valve \u2014 bas\u0131n\xe7 tahliye valfi\n\u2022 Actuator \u2014 akt\xfcat\xf6r (silindir)\n\u2022 Selector valve \u2014 se\xe7ici valf\n\u2022 Accumulator \u2014 ak\xfcm\xfclat\xf6r (bas\u0131n\xe7 depolamak i\xe7in)\n\u2022 Filter element \u2014 filtre eleman\u0131\n\n**Ar\u0131za terimleri:**\n\u2022 External leakage \u2014 d\u0131\u015f s\u0131z\u0131nt\u0131 (g\xf6r\xfcn\xfcr)\n\u2022 Internal leakage \u2014 i\xe7 s\u0131z\u0131nt\u0131 (pistondan bypass)\n\u2022 Low pressure \u2014 d\xfc\u015f\xfck bas\u0131n\xe7 (pump, filter, leak)\n\u2022 Aeration \u2014 s\u0131v\u0131ya hava kar\u0131\u015fmas\u0131 (k\xf6p\xfck)\n\u2022 Contamination \u2014 kirlilik (par\xe7ac\u0131k, su)\n\n**AMM talimat ifadeleri:**\n"Depressurise hydraulic system before maintenance."\n"Bleed air from system after component replacement."\n"Check fluid level at [COLD/HOT] indication on sight glass."',null,null,null)
B.a4_=s(["turn on the hydraulic pump","relieve accumulated hydraulic pressure before working on the system","add hydraulic fluid before starting work","run a ground check to verify pressure"],t.s)
B.al9=new A.x(-252,B.t,2122,'"Depressurise hydraulic system before maintenance" means:',B.a4_,1,B.p,null,null,null)
B.aea=s(["correct fluid viscosity","air bubbles mixed with hydraulic fluid, causing foaming","normal fluid circulation","high fluid temperature"],t.s)
